    63→export const generateOptimizedRobotsTxt = (urlStr: string): string => {
    64→  let hostname = urlStr;
    65→  let protocol = 'https';
    66→  
    67→  try {
    68→    const urlObj = new URL(urlStr.startsWith('http') ? urlStr : `https://${urlStr}`);
    69→    hostname = urlObj.hostname;
    70→    protocol = urlObj.protocol.replace(':', '');
    71→  } catch (e) {
    72→    // Fallback if URL is invalid
    73→  }
    74→
    75→  const platform = detectPlatform(urlStr);
    76→  const date = new Date().toISOString().split('T')[0];
    77→
    78→  let content = `# Robots.txt Optimized for AEO (Answer Engine Optimization)
    79→# Generated by CitedBy.ai on ${date}
    80→# Domain: ${hostname}
    81→# Detected Architecture: ${platform.name}
    82→
    83→# ==========================================
    84→# PART 1: AI & LLM AGENTS (ALLOW LIST)
